import React from 'react';
import { BrowserRouter as Router, Route, Switch } from 'react-router-dom';

import Home from './pages/home/Home';
import Services from './pages/services/Services';
import Blogs from './pages/blogs/Blogs';
import About from './pages/about/About';
import Contactus from './pages/contactus/ContactUs';
import Quiz from './pages/quiz/Quiz';
import Booking from './pages/services/booking/Booking';
import SingleBlog from './pages/blogs/singleblog/SingleBlog';
import ThankYouMessage from './pages/thankyoumessage/ThankYouMessage';
import CookiesPolicy from './pages/policies/cookiespolicy/CookiesPolicy';
import PrivacyPolicy from './pages/policies/privacypolicy/PrivacyPolicy';
import LegalNotice from './pages/policies/legalnotice/LegalNotice';

const App = () => {
  return (
    <Router>
      <Switch>
        <Route path="/" exact component={Home} />
        <Route path="/services" component={Services} />
        <Route path="/blogs" component={Blogs} />
        <Route path="/about" component={About} />
        <Route path="/contactus" component={Contactus} />
        <Route path="/quiz" component={Quiz} />
        <Route path="/booking" component={Booking} />
        <Route path="/singleblog" component={SingleBlog} />
        <Route path="/thankyoumessage" component={ThankYouMessage} />
        <Route path="/cookiespolicy" component={CookiesPolicy} />
        <Route path="/privacypolicy" component={PrivacyPolicy} />
        <Route path="/legalnotice" component={LegalNotice} />
      </Switch>
    </Router>
  );
};

export default App;
